      feet_units = any("Feet" in t.predicate for t in triples)

      # Build a simple list of subject‑predicate‑object phrases.
      parts: list[str] = []
      for t in triples:
          generator = phrase_map.get(t.predicate)
          if generator:
              phrase = generator(t.object)
          else:
              phrase = f"{t.predicate} {t.object}"
          parts.append(f"{t.subject} {phrase}")

      # Combine the parts into one fluent sentence.
      if not parts:
          return ""
      if len(parts) == 1:
          sentence = parts[0] + "."
      elif len(parts) == 2:
          sentence = parts[0] + " and " + parts[1] + "."
      else:
          sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
      return sentence[0].upper() + sentence[1:]
